func DefaultBuildHandlerChain(apiHandler http.Handler, c *Config) http.Handler {
        handler := apiHandler

        handler = filterlatency.TrackCompleted(handler)
        handler = genericapifilters.WithAuthorization(handler, c.Authorization.Authorizer, c.Serializer)
        handler = filterlatency.TrackStarted(handler, c.TracerProvider, "authorization")

        if c.FlowControl != nil {
                workEstimatorCfg := flowcontrolrequest.DefaultWorkEstimatorConfig()
                requestWorkEstimator := flowcontrolrequest.NewWorkEstimator(
                        c.StorageObjectCountTracker.Get, c.FlowControl.GetInterestedWatchCount, workEstimatorCfg, c.FlowControl.GetMaxSeats)
                handler = filterlatency.TrackCompleted(handler)
                handler = genericfilters.WithPriorityAndFairness(handler, c.LongRunningFunc, c.FlowControl, requestWorkEstimator, c.RequestTimeout/4)
                handler = filterlatency.TrackStarted(handler, c.TracerProvider, "priorityandfairness")
        } else {
                handler = genericfilters.WithMaxInFlightLimit(handler, c.MaxRequestsInFlight, c.MaxMutatingRequestsInFlight, c.LongRunningFunc)
        }

        handler = filterlatency.TrackCompleted(handler)
        if c.FeatureGate.Enabled(genericfeatures.ConstrainedImpersonation) {
                handler = impersonation.WithConstrainedImpersonation(handler, c.Authorization.Authorizer, c.Serializer)
                handler = filterlatency.TrackStarted(handler, c.TracerProvider, "constrainedimpersonation")
        } else {
                handler = impersonation.WithImpersonation(handler, c.Authorization.Authorizer, c.Serializer)
                handler = filterlatency.TrackStarted(handler, c.TracerProvider, "impersonation")
        }

        handler = filterlatency.TrackCompleted(handler)
        handler = genericapifilters.WithAudit(handler, c.AuditBackend, c.AuditPolicyRuleEvaluator, c.LongRunningFunc)
        handler = filterlatency.TrackStarted(handler, c.TracerProvider, "audit")

        failedHandler := genericapifilters.Unauthorized(c.Serializer)
        failedHandler = genericapifilters.WithFailedAuthenticationAudit(failedHandler, c.AuditBackend, c.AuditPolicyRuleEvaluator)

        // WithTracing comes after authentication so we can allow authenticated
        // clients to influence sampling.
        if c.FeatureGate.Enabled(genericfeatures.APIServerTracing) {
                handler = genericapifilters.WithTracing(handler, c.TracerProvider)
        }
        failedHandler = filterlatency.TrackCompleted(failedHandler)
        handler = filterlatency.TrackCompleted(handler)
        handler = genericapifilters.WithAuthentication(handler, c.Authentication.Authenticator, failedHandler, c.Authentication.APIAudiences, c.Authentication.RequestHeaderConfig)
        handler = filterlatency.TrackStarted(handler, c.TracerProvider, "authentication")

        handler = genericfilters.WithCORS(handler, c.CorsAllowedOriginList, nil, nil, nil, "true")

        // WithWarningRecorder must be wrapped by the timeout handler
        // to make the addition of warning headers threadsafe
        handler = genericapifilters.WithWarningRecorder(handler)

        // WithTimeoutForNonLongRunningRequests will call the rest of the request handling in a go-routine with the
        // context with deadline. The go-routine can keep running, while the timeout logic will return a timeout to the client.
        handler = genericfilters.WithTimeoutForNonLongRunningRequests(handler, c.LongRunningFunc)

        handler = genericapifilters.WithRequestDeadline(handler, c.AuditBackend, c.AuditPolicyRuleEvaluator,
                c.LongRunningFunc, c.Serializer, c.RequestTimeout)

func (e *Store) create(ctx context.Context, obj runtime.Object, createValidation rest.ValidateObjectFunc, options *metav1.CreateOptions) (runtime.Object, error) {
        var finishCreate FinishFunc = finishNothing

        // Init metadata as early as possible.
        if objectMeta, err := meta.Accessor(obj); err != nil {
                return nil, err
        } else {
                rest.FillObjectMetaSystemFields(objectMeta)
                if len(objectMeta.GetGenerateName()) > 0 && len(objectMeta.GetName()) == 0 {
                        objectMeta.SetName(e.CreateStrategy.GenerateName(objectMeta.GetGenerateName()))
                }
        }

        if e.BeginCreate != nil {
                fn, err := e.BeginCreate(ctx, obj, options)
                if err != nil {
                        return nil, err
                }
                finishCreate = fn
                defer func() {
                        finishCreate(ctx, false)
                }()
        }

        if err := rest.BeforeCreate(e.CreateStrategy, ctx, obj); err != nil {
                return nil, err
        }
        // at this point we have a fully formed object.  It is time to call the validators that the apiserver
        // handling chain wants to enforce.
        if createValidation != nil {
                if err := createValidation(ctx, obj.DeepCopyObject()); err != nil {
                        return nil, err
                }
        }

        name, err := e.ObjectNameFunc(obj)
        if err != nil {
                return nil, err
        }
        key, err := e.KeyFunc(ctx, name)
        if err != nil {
                return nil, err
        }
        qualifiedResource := e.qualifiedResourceFromContext(ctx)
        ttl, err := e.calculateTTL(obj, 0, false)
        if err != nil {
                return nil, err
        }
        out := e.NewFunc()
        if err := e.Storage.Create(ctx, key, obj, out, ttl, dryrun.IsDryRun(options.DryRun)); err != nil {
                err = storeerr.InterpretCreateError(err, qualifiedResource, name)
                err = rest.CheckGeneratedNameError(ctx, e.CreateStrategy, err, obj)
                if !apierrors.IsAlreadyExists(err) {
                        return nil, err
                }
                if errGet := e.Storage.Get(ctx, key, storage.GetOptions{}, out); errGet != nil {
                        return nil, err
                }
                accessor, errGetAcc := meta.Accessor(out)
                if errGetAcc != nil {
                        return nil, err
                }
                if accessor.GetDeletionTimestamp() != nil {
                        msg := &err.(*apierrors.StatusError).ErrStatus.Message
                        *msg = fmt.Sprintf("object is being deleted: %s", *msg)
                }
                return nil, err
        }
        // The operation has succeeded.  Call the finish function if there is one,
        // and then make sure the defer doesn't call it again.
        fn := finishCreate
        finishCreate = finishNothing
        fn(ctx, true)

        if e.AfterCreate != nil {
                e.AfterCreate(out, options)
        }
        if e.Decorator != nil {
                e.Decorator(out)
        }
        return out, nil
}

// ShouldDeleteDuringUpdate is the default function for
// checking if an object should be deleted during an update.
// It checks if the new object has no finalizers,
// the existing object's deletionTimestamp is set, and
// the existing object's deletionGracePeriodSeconds is 0 or nil
func ShouldDeleteDuringUpdate(ctx context.Context, key string, obj, existing runtime.Object) bool {
        newMeta, err := meta.Accessor(obj)
        if err != nil {
                utilruntime.HandleError(err)
                return false
        }
        oldMeta, err := meta.Accessor(existing)
        if err != nil {
                utilruntime.HandleError(err)
                return false
        }
        if len(newMeta.GetFinalizers()) > 0 {
                // don't delete with finalizers remaining in the new object
                return false
        }
        if oldMeta.GetDeletionTimestamp() == nil {
                // don't delete if the existing object hasn't had a delete request made
                return false
        }
        // delete if the existing object has no grace period or a grace period of 0
        return oldMeta.GetDeletionGracePeriodSeconds() == nil || *oldMeta.GetDeletionGracePeriodSeconds() == 0
}

// deleteWithoutFinalizers handles deleting an object ignoring its finalizer list.
// Used for objects that are either been finalized or have never initialized.
func (e *Store) deleteWithoutFinalizers(ctx context.Context, name, key string, obj runtime.Object, preconditions *storage.Preconditions, options *metav1.DeleteOptions) (runtime.Object, bool, error) {

c.LongRunningFunc, c.Serializer, c.RequestTimeout)
        handler = genericfilters.WithWaitGroup(handler, c.LongRunningFunc, c.NonLongRunningRequestWaitGroup)
        if c.ShutdownWatchTerminationGracePeriod > 0 {
                handler = genericfilters.WithWatchTerminationDuringShutdown(handler, c.lifecycleSignals, c.WatchRequestWaitGroup)
        }
        if c.SecureServing != nil && !c.SecureServing.DisableHTTP2 && c.GoawayChance > 0 {
                handler = genericfilters.WithProbabilisticGoaway(handler, c.GoawayChance)
        }
        handler = genericapifilters.WithCacheControl(handler)
        handler = genericfilters.WithHSTS(handler, c.HSTSDirectives)
        if c.ShutdownSendRetryAfter {
                handler = genericfilters.WithRetryAfter(handler, c.lifecycleSignals.NotAcceptingNewRequest.Signaled())
        }
        handler = genericfilters.WithHTTPLogging(handler)
        handler = genericapifilters.WithLatencyTrackers(handler)
        // WithRoutine will execute future handlers in a separate goroutine and serving
        // handler in current goroutine to minimize the stack memory usage. It must be
        // after WithPanicRecover() to be protected from panics.
        if c.FeatureGate.Enabled(genericfeatures.APIServingWithRoutine) {
                handler = routine.WithRoutine(handler, c.LongRunningFunc)
        }
        handler = genericapifilters.WithRequestInfo(handler, c.RequestInfoResolver)
        handler = genericapifilters.WithRequestReceivedTimestamp(handler)
        handler = genericapifilters.WithMuxAndDiscoveryComplete(handler, c.lifecycleSignals.MuxAndDiscoveryComplete.Signaled())
        handler = genericfilters.WithPanicRecovery(handler, c.RequestInfoResolver)
        handler = genericapifilters.WithAuditInit(handler)
        return handler
}

func installAPI(name string, s *GenericAPIServer, c *Config) {
        if c.EnableIndex {
                routes.Index{}.Install(s.listedPathProvider, s.Handler.NonGoRestfulMux)
        }
        if c.EnableProfiling {
                routes.Profiling{}.Install(s.Handler.NonGoRestfulMux)
                if c.EnableContentionProfiling {
                        goruntime.SetBlockProfileRate(1)
                }
                // so far, only logging related endpoints are considered valid to add for these debug flags.
                routes.DebugFlags{}.Install(s.Handler.NonGoRestfulMux, "v", routes.StringFlagPutHandler(logs.GlogSetter))
        }
        if s.UnprotectedDebugSocket != nil {
                s.UnprotectedDebugSocket.InstallProfiling()
                s.UnprotectedDebugSocket.InstallDebugFlag("v", routes.StringFlagPutHandler(logs.GlogSetter))
                if c.EnableContentionProfiling {
                        goruntime.SetBlockProfileRate(1)
                }
        }

        if c.EnableMetrics {
                if c.EnableProfiling {
                        routes.MetricsWithReset{}.Install(s.Handler.NonGoRestfulMux)
                        slis.SLIMetricsWithReset{}.Install(s.Handler.NonGoRestfulMux)
                } else {
                        routes.DefaultMetrics{}.Install(s.Handler.NonGoRestfulMux)
                        slis.SLIMetrics{}.Install(s.Handler.NonGoRestfulMux)
                }
        }

        routes.Version{Version: c.EffectiveVersion.Info()}.Install(s.Handler.GoRestfulContainer)

        if c.EnableDiscovery {
                wrapped := discoveryendpoint.WrapAggregatedDiscoveryToHandler(s.DiscoveryGroupManager, s.AggregatedDiscoveryGroupManager, s.PeerAggregatedDiscoveryManager)
                s.Handler.GoRestfulContainer.Add(wrapped.GenerateWebService("/apis", metav1.APIGroupList{}))
        }
        if c.FlowControl != nil {
                c.FlowControl.Install(s.Handler.NonGoRestfulMux)
        }
}

