// Feature is the name of each feature in storage that we check in feature_support_checker.
type Feature = string

// RequestWatchProgress is an etcd feature that may use to check if it supported or not.
var RequestWatchProgress Feature = "RequestWatchProgress"

// Versioner abstracts setting and retrieving metadata fields from database response
// onto the object ot list. It is required to maintain storage invariants - updating an
// object twice with the same data except for the ResourceVersion and SelfLink must be
// a no-op. A resourceVersion of type uint64 is a 'raw' resourceVersion,
// intended to be sent directly to or from the backend. A resourceVersion of
// type string is a 'safe' resourceVersion, intended for consumption by users.
type Versioner interface {
        // UpdateObject sets storage metadata into an API object. Returns an error if the object
        // cannot be updated correctly. May return nil if the requested object does not need metadata
        // from database.
        UpdateObject(obj runtime.Object, resourceVersion uint64) error
        // UpdateList sets the resource version into an API list object. Returns an error if the object
        // cannot be updated correctly. May return nil if the requested object does not need metadata from
        // database. continueValue is optional and indicates that more results are available if the client
        // passes that value to the server in a subsequent call. remainingItemCount indicates the number
        // of remaining objects if the list is partial. The remainingItemCount field is omitted during
        // serialization if it is set to nil.
        UpdateList(obj runtime.Object, resourceVersion uint64, continueValue string, remainingItemCount *int64) error
        // PrepareObjectForStorage should set SelfLink and ResourceVersion to the empty value. Should
        // return an error if the specified object cannot be updated.
        PrepareObjectForStorage(obj runtime.Object) error
        // ObjectResourceVersion returns the resource version (for persistence) of the specified object.
        // Should return an error if the specified object does not have a persistable version.
        ObjectResourceVersion(obj runtime.Object) (uint64, error)

        // ParseResourceVersion takes a resource version argument and
        // converts it to the storage backend. For watch we should pass to helper.Watch().
        // Because resourceVersion is an opaque value, the default watch
        // behavior for non-zero watch is to watch the next value (if you pass
        // "1", you will see updates from "2" onwards).
        ParseResourceVersion(resourceVersion string) (uint64, error)
}

// ResponseMeta contains information about the database metadata that is associated with
// an object. It abstracts the actual underlying objects to prevent coupling with concrete
// database and to improve testability.
type ResponseMeta struct {
        // TTL is the time to live of the node that contained the returned object. It may be
        // zero or negative in some cases (objects may be expired after the requested
        // expiration time due to server lag).
        TTL int64
        // The resource version of the node that contained the returned object.
        ResourceVersion uint64
}

// IndexerFunc is a function that for a given object computes
// `<value of an index>` for a particular `<index>`.
type IndexerFunc func(obj runtime.Object) string

// IndexerFuncs is a mapping from `<index name>` to function that
// for a given object computes `<value for that index>`.
type IndexerFuncs map[string]IndexerFunc

// Everything accepts all objects.
var Everything = SelectionPredicate{
        Label: labels.Everything(),
        Field: fields.Everything(),
}

// MatchValue defines a pair (`<index name>`, `<value for that index>`).
type MatchValue struct {
        IndexName string
        Value     string
}

// Pass an UpdateFunc to Interface.GuaranteedUpdate to make an update
// that is guaranteed to succeed.
// See the comment for GuaranteedUpdate for more details.
type UpdateFunc func(input runtime.Object, res ResponseMeta) (output runtime.Object, ttl *uint64, err error)

// ValidateObjectFunc is a function to act on a given object. An error may be returned
// if the hook cannot be completed. The function may NOT transform the provided
// object.
// NOTE: the object in obj may be nil if it cannot be read from the
// storage, due to transformation or decode error.
type ValidateObjectFunc func(ctx context.Context, obj runtime.Object) error

// ValidateAllObjectFunc is a "admit everything" instance of ValidateObjectFunc.
func ValidateAllObjectFunc(ctx context.Context, obj runtime.Object) error {
        return nil
}

// Preconditions must be fulfilled before an operation (update, delete, etc.) is carried out.
type Preconditions struct {
        // Specifies the target UID.
        // +optional
        UID *types.UID `json:"uid,omitempty"`
        // Specifies the target ResourceVersion
        // +optional
        ResourceVersion *string `json:"resourceVersion,omitempty"`
}

// NewUIDPreconditions returns a Preconditions with UID set.
func NewUIDPreconditions(uid string) *Preconditions {
        u := types.UID(uid)
        return &Preconditions{UID: &u}
}

func (p *Preconditions) Check(key string, obj runtime.Object) error {
        if p == nil {
                return nil
        }
        objMeta, err := meta.Accessor(obj)
        if err != nil {
                return NewInternalError(
                        fmt.Errorf("can't enforce preconditions %v on un-introspectable object %v, got error: %w",
                                *p,
                                obj,
                                err))
        }
        if p.UID != nil && *p.UID != objMeta.GetUID() {
                err := fmt.Sprintf(
                        "Precondition failed: UID in precondition: %v, UID in object meta: %v",
                        *p.UID,
                        objMeta.GetUID())
                return NewInvalidObjError(key, err)
        }
        if p.ResourceVersion != nil && *p.ResourceVersion != objMeta.GetResourceVersion() {
                err := fmt.Sprintf(
                        "Precondition failed: ResourceVersion in precondition: %v, ResourceVersion in object meta: %v",
                        *p.ResourceVersion,
                        objMeta.GetResourceVersion())
                return NewInvalidObjError(key, err)
        }
        return nil
}

// Interface offers a common interface for object marshaling/unmarshaling operations and
// hides all the storage-related operations behind it.
type Interface interface {
        // Returns Versioner associated with this interface.
        Versioner() Versioner

        // Create adds a new object at a key unless it already exists. 'ttl' is time-to-live
        // in seconds (0 means forever). If no error is returned and out is not nil, out will be
        // set to the read value from database.
        Create(ctx context.Context, key string, obj, out runtime.Object, ttl uint64) error

        // Delete removes the specified key and returns the value that existed at that spot.
        // If key didn't exist, it will return NotFound storage error.
        // If 'cachedExistingObject' is non-nil, it can be used as a suggestion about the
        // current version of the object to avoid read operation from storage to get it.
        // However, the implementations have to retry in case suggestion is stale.
        Delete(
                ctx context.Context, key string, out runtime.Object, preconditions *Preconditions,
                validateDeletion ValidateObjectFunc, cachedExistingObject runtime.Object, opts DeleteOptions) error

        // Watch begins watching the specified key. Events are decoded into API objects,
        // and any items selected by 'p' are sent down to returned watch.Interface.
        // resourceVersion may be used to specify what version to begin watching,
        // which should be the current resourceVersion, and no longer rv+1
        // (e.g. reconnecting without missing any updates).
        // If resource version is "0", this interface will get current object at given key
        // and send it in an "ADDED" event, before watch starts.
        Watch(ctx context.Context, key string, opts ListOptions) (watch.Interface, error)

        // Get unmarshals object found at key into objPtr. On a not found error, will either
        // return a zero object of the requested type, or an error, depending on 'opts.ignoreNotFound'.
        // Treats empty responses and nil response nodes exactly like a not found error.
        // The returned contents may be delayed, but it is guaranteed that they will
        // match 'opts.ResourceVersion' according 'opts.ResourceVersionMatch'.

// match 'opts.ResourceVersion' according 'opts.ResourceVersionMatch'.
        Get(ctx context.Context, key string, opts GetOptions, objPtr runtime.Object) error

        // GetList unmarshalls objects found at key into a *List api object (an object
        // that satisfies runtime.IsList definition).
        // If 'opts.Recursive' is false, 'key' is used as an exact match. If `opts.Recursive'
        // is true, 'key' is used as a prefix.
        // The returned contents may be delayed, but it is guaranteed that they will
        // match 'opts.ResourceVersion' according 'opts.ResourceVersionMatch'.
        GetList(ctx context.Context, key string, opts ListOptions, listObj runtime.Object) error

        // GuaranteedUpdate keeps calling 'tryUpdate()' to update key 'key' (of type 'destination')
        // retrying the update until success if there is index conflict.
        // Note that object passed to tryUpdate may change across invocations of tryUpdate() if
        // other writers are simultaneously updating it, so tryUpdate() needs to take into account
        // the current contents of the object when deciding how the update object should look.
        // If the key doesn't exist, it will return NotFound storage error if ignoreNotFound=false
        // else `destination` will be set to the zero value of it's type.
        // If the eventual successful invocation of `tryUpdate` returns an output with the same serialized
        // contents as the input, it won't perform any update, but instead set `destination` to an object with those
        // contents.
        // If 'cachedExistingObject' is non-nil, it can be used as a suggestion about the
        // current version of the object to avoid read operation from storage to get it.
        // However, the implementations have to retry in case suggestion is stale.
        //
        // Example:
        //
        // s := /* implementation of Interface */
        // err := s.GuaranteedUpdate(
        //     "myKey", &MyType{}, true, preconditions,
        //     func(input runtime.Object, res ResponseMeta) (runtime.Object, *uint64, error) {
        //       // Before each invocation of the user defined function, "input" is reset to
        //       // current contents for "myKey" in database.
        //       curr := input.(*MyType)  // Guaranteed to succeed.
        //
        //       // Make the modification
        //       curr.Counter++
        //
        //       // Return the modified object - return an error to stop iterating. Return
        //       // a uint64 to alter the TTL on the object, or nil to keep it the same value.
        //       return cur, nil, nil
        //    }, cachedExistingObject
        // )
        GuaranteedUpdate(
                ctx context.Context, key string, destination runtime.Object, ignoreNotFound bool,
                preconditions *Preconditions, tryUpdate UpdateFunc, cachedExistingObject runtime.Object) error

        // Stats returns storage stats.
        Stats(ctx context.Context) (Stats, error)

        // ReadinessCheck checks if the storage is ready for accepting requests.
        ReadinessCheck() error

        // RequestWatchProgress requests the a watch stream progress status be sent in the
        // watch response stream as soon as possible.
        // Used for monitor watch progress even if watching resources with no changes.
        //
        // If watch is lagging, progress status might:
        // * be pointing to stale resource version. Use etcd KV request to get linearizable resource version.
        // * not be delivered at all. It's recommended to poll request progress periodically.
        //
        // Note: Only watches with matching context grpc metadata will be notified.
        // https://github.com/kubernetes/kubernetes/blob/9325a57125e8502941d1b0c7379c4bb80a678d5c/vendor/go.etcd.io/etcd/client/v3/watch.go#L1037-L1042
        //
        // TODO: Remove when storage.Interface will be separate from etc3.store.
        // Deprecated: Added temporarily to simplify exposing RequestProgress for watch cache.
        RequestWatchProgress(ctx context.Context) error

        // GetCurrentResourceVersion gets the current resource version from etcd.
        // This method issues an empty list request and reads only the ResourceVersion from the object metadata
        GetCurrentResourceVersion(ctx context.Context) (uint64, error)

        // EnableResourceSizeEstimation enables estimating resource size by providing function get keys from storage.
        EnableResourceSizeEstimation(KeysFunc) error

        // CompactRevision returns latest observed revision that was compacted.
        // Without ListFromCacheSnapshot enabled only locally executed compaction will be observed.
        // Returns 0 if no compaction was yet observed.
        CompactRevision() int64
}

// KeysFunc is a function prototype to fetch keys from storage.
type KeysFunc func(context.Context) ([]string, error)

// GetOptions provides the options that may be provided for storage get operations.
type GetOptions struct {
        // IgnoreNotFound determines what is returned if the requested object is not found. If
        // true, a zero object is returned. If false, an error is returned.
        IgnoreNotFound bool
        // ResourceVersion provides a resource version constraint to apply to the get operation
        // as a "not older than" constraint: the result contains data at least as new as the provided
        // ResourceVersion. The newest available data is preferred, but any data not older than this
        // ResourceVersion may be served.
        ResourceVersion string
}

// ListOptions provides the options that may be provided for storage list operations.
type ListOptions struct {
        // ResourceVersion provides a resource version constraint to apply to the list operation
        // as a "not older than" constraint: the result contains data at least as new as the provided
        // ResourceVersion. The newest available data is preferred, but any data not older than this
        // ResourceVersion may be served.
        ResourceVersion string
        // ResourceVersionMatch provides the rule for how the resource version constraint applies. If set
        // to the default value "" the legacy resource version semantic apply.
        ResourceVersionMatch metav1.ResourceVersionMatch
        // Predicate provides the selection rules for the list operation.
        Predicate SelectionPredicate
        // Recursive determines whether the list or watch is defined for a single object located at the
        // given key, or for the whole set of objects with the given key as a prefix.
        Recursive bool
        // ProgressNotify determines whether storage-originated bookmark (progress notify) events should
        // be delivered to the users. The option is ignored for non-watch requests.
        //
        // Firstly, note that this field is different from the Predicate.AllowWatchBookmarks field.
        // Secondly, this field is intended for internal clients only such as the watch cache.
        //
        // This means that external clients do not have the ability to set this field directly.
        // For example by setting the allowWatchBookmarks query parameter.
        //
        // The motivation for this approach is the fact that the frequency

func CreateServerChain(config CompletedConfig) (*aggregatorapiserver.APIAggregator, error) {
        notFoundHandler := notfoundhandler.New(config.KubeAPIs.ControlPlane.Generic.Serializer, genericapifilters.NoMuxAndDiscoveryIncompleteKey)
        apiExtensionsServer, err := config.ApiExtensions.New(genericapiserver.NewEmptyDelegateWithCustomHandler(notFoundHandler))
        if err != nil {
                return nil, err
        }
        crdAPIEnabled := config.ApiExtensions.GenericConfig.MergedResourceConfig.ResourceEnabled(apiextensionsv1.SchemeGroupVersion.WithResource("customresourcedefinitions"))

        kubeAPIServer, err := config.KubeAPIs.New(apiExtensionsServer.GenericAPIServer)
        if err != nil {
                return nil, err
        }

        // aggregator comes last in the chain
        aggregatorServer, err := controlplaneapiserver.CreateAggregatorServer(config.Aggregator, kubeAPIServer.ControlPlane.GenericAPIServer, apiExtensionsServer.Informers.Apiextensions().V1().CustomResourceDefinitions(), crdAPIEnabled, apiVersionPriorities)
        if err != nil {
                // we don't need special handling for innerStopCh because the aggregator server doesn't create any go routines
                return nil, err
        }

        return aggregatorServer, nil
}

// CreateKubeAPIServerConfig creates all the resources for running the API server, but runs none of them
func CreateKubeAPIServerConfig(
        opts options.CompletedOptions,
        genericConfig *genericapiserver.Config,
        versionedInformers clientgoinformers.SharedInformerFactory,
        storageFactory *serverstorage.DefaultStorageFactory,
) (
        *controlplane.Config,
        aggregatorapiserver.ServiceResolver,
        []admission.PluginInitializer,
        error,
) {
        // global stuff
        capabilities.Setup(opts.AllowPrivileged, opts.MaxConnectionBytesPerSec)

        // additional admission initializers
        kubeAdmissionConfig := &kubeapiserveradmission.Config{}
        kubeInitializers, err := kubeAdmissionConfig.New()
        if err != nil {
                return nil, nil, nil, fmt.Errorf("failed to create admission plugin initializer: %w", err)
        }

        serviceResolver, err := buildServiceResolver(opts.EnableAggregatorRouting, genericConfig.LoopbackClientConfig.Host, versionedInformers)
        if err != nil {
                return nil, nil, nil, fmt.Errorf("error building service resolver: %w", err)
        }
        controlplaneConfig, admissionInitializers, err := controlplaneapiserver.CreateConfig(opts.CompletedOptions, genericConfig, versionedInformers, storageFactory, serviceResolver, kubeInitializers)
        if err != nil {
                return nil, nil, nil, err
        }

        config := &controlplane.Config{
                ControlPlane: *controlplaneConfig,
                Extra: controlplane.Extra{
                        KubeletClientConfig: opts.KubeletConfig,

                        ServiceIPRange:          opts.PrimaryServiceClusterIPRange,
                        APIServerServiceIP:      opts.APIServerServiceIP,
                        SecondaryServiceIPRange: opts.SecondaryServiceClusterIPRange,

                        APIServerServicePort: 443,

                        ServiceNodePortRange:      opts.ServiceNodePortRange,
                        KubernetesServiceNodePort: opts.KubernetesServiceNodePort,

                        EndpointReconcilerType: reconcilers.Type(opts.EndpointReconcilerType),
                        MasterCount:            opts.MasterCount,
                },
        }

        if config.ControlPlane.Generic.EgressSelector != nil {
                // Use the config.ControlPlane.Generic.EgressSelector lookup to find the dialer to connect to the kubelet
                config.Extra.KubeletClientConfig.Lookup = config.ControlPlane.Generic.EgressSelector.Lookup

                // Use the config.ControlPlane.Generic.EgressSelector lookup as the transport used by the "proxy" subresources.
                networkContext := egressselector.Cluster.AsNetworkContext()
                dialer, err := config.ControlPlane.Generic.EgressSelector.Lookup(networkContext)
                if err != nil {
                        return nil, nil, nil, err
                }
                c := config.ControlPlane.Extra.ProxyTransport.Clone()
                c.DialContext = dialer
                config.ControlPlane.ProxyTransport = c
        }

        return config, serviceResolver, admissionInitializers, nil
}

var testServiceResolver webhook.ServiceResolver

// SetServiceResolverForTests allows the service resolver to be overridden during tests.
// Tests using this function must run serially as this function is not safe to call concurrently with server start.
func SetServiceResolverForTests(resolver webhook.ServiceResolver) func() {
        if testServiceResolver != nil {
                panic("test service resolver is set: tests are either running concurrently or clean up was skipped")
        }

        testServiceResolver = resolver

        return func() {
                testServiceResolver = nil
        }
}

func buildServiceResolver(enabledAggregatorRouting bool, hostname string, informer clientgoinformers.SharedInformerFactory) (webhook.ServiceResolver, error) {
        if testServiceResolver != nil {
                return testServiceResolver, nil
        }

        endpointSliceGetter, err := proxy.NewEndpointSliceIndexerGetter(informer.Discovery().V1().EndpointSlices())
        if err != nil {
                return nil, err
        }

        var serviceResolver webhook.ServiceResolver
        if enabledAggregatorRouting {
                serviceResolver = aggregatorapiserver.NewEndpointServiceResolver(
                        informer.Core().V1().Services().Lister(),
                        endpointSliceGetter,
                )
        } else {
                serviceResolver = aggregatorapiserver.NewClusterIPServiceResolver(
                        informer.Core().V1().Services().Lister(),
                )
        }

        // resolve kubernetes.default.svc locally
        if localHost, err := url.Parse(hostname); err == nil {
                serviceResolver = aggregatorapiserver.NewLoopbackServiceResolver(serviceResolver, localHost)
        }
        return serviceResolver, nil
}

func (s *GenericAPIServer) PrepareRun() preparedGenericAPIServer {
        s.delegationTarget.PrepareRun()

        if s.openAPIConfig != nil && !s.skipOpenAPIInstallation {
                s.OpenAPIVersionedService, s.StaticOpenAPISpec = routes.OpenAPI{
                        Config: s.openAPIConfig,
                }.InstallV2(s.Handler.GoRestfulContainer, s.Handler.NonGoRestfulMux)
        }

        if s.openAPIV3Config != nil && !s.skipOpenAPIInstallation {
                s.OpenAPIV3VersionedService = routes.OpenAPI{
                        V3Config: s.openAPIV3Config,
                }.InstallV3(s.Handler.GoRestfulContainer, s.Handler.NonGoRestfulMux)
        }

        s.installHealthz()
        s.installLivez()

        // as soon as shutdown is initiated, readiness should start failing
        readinessStopCh := s.lifecycleSignals.ShutdownInitiated.Signaled()
        err := s.addReadyzShutdownCheck(readinessStopCh)
        if err != nil {
                klog.Errorf("Failed to install readyz shutdown check %s", err)
        }
        s.installReadyz()

        if utilfeature.DefaultFeatureGate.Enabled(zpagesfeatures.ComponentStatusz) {
                statusz.Install(s.Handler.NonGoRestfulMux, "apiserver", statusz.NewRegistry(s.EffectiveVersion, statusz.WithListedPaths(s.ListedPaths())))
        }

        return preparedGenericAPIServer{s}
}

// Run spawns the secure http server. It only returns if stopCh is closed
// or the secure port cannot be listened on initially.
//
// Deprecated: use RunWithContext instead. Run will not get removed to avoid
// breaking consumers, but should not be used in new code.
func (s preparedGenericAPIServer) Run(stopCh <-chan struct{}) error {
        ctx := wait.ContextForChannel(stopCh)
        return s.RunWithContext(ctx)
}

// RunWithContext spawns the secure http server. It only returns if ctx is canceled
// or the secure port cannot be listened on initially.
// This is the diagram of what contexts/channels/signals are dependent on each other:
//
// |                                   ctx
// |                                    |
// |           ---------------------------------------------------------
// |           |                                                       |
// |    ShutdownInitiated (shutdownInitiatedCh)                        |
// |           |                                                       |
// | (ShutdownDelayDuration)                                    (PreShutdownHooks)
// |           |                                                       |
// |  AfterShutdownDelayDuration (delayedStopCh)   PreShutdownHooksStopped (preShutdownHooksHasStoppedCh)
// |           |                                                       |
// |           |-------------------------------------------------------|
// |                                    |
// |                                    |
// |               NotAcceptingNewRequest (notAcceptingNewRequestCh)
// |                                    |
// |                                    |
// |           |----------------------------------------------------------------------------------|
// |           |                        |              |                                          |
// |        [without                 [with             |                                          |
// | ShutdownSendRetryAfter]  ShutdownSendRetryAfter]  |                                          |
// |           |                        |              |                                          |
// |           |                        ---------------|                                          |
// |           |                                       |                                          |
// |           |                      |----------------|-----------------------|                  |
// |           |                      |                                        |                  |
// |           |         (NonLongRunningRequestWaitGroup::Wait)   (WatchRequestWaitGroup::Wait)   |
// |           |                      |                                        |                  |
// |           |                      |------------------|---------------------|                  |
// |           |                                         |                                        |
// |           |                         InFlightRequestsDrained (drainedCh)                      |
// |           |                                         |                                        |
// |           |-------------------|---------------------|----------------------------------------|
// |                               |                     |
// |                       stopHttpServerCtx     (AuditBackend::Shutdown())
// |                               |
// |                       listenerStoppedCh
// |                               |
// |      HTTPServerStoppedListening (httpServerStoppedListeningCh)
func (s preparedGenericAPIServer) RunWithContext(ctx context.Context) error {
        stopCh := ctx.Done()
        delayedStopCh := s.lifecycleSignals.AfterShutdownDelayDuration
        shutdownInitiatedCh := s.lifecycleSignals.ShutdownInitiated

        // Clean up resources on shutdown.
        defer s.Destroy()

        // If UDS profiling is enabled, start a local http server listening on that socket
        if s.UnprotectedDebugSocket != nil {
                go func() {
                        defer utilruntime.HandleCrashWithContext(ctx)
                        klog.Error(s.UnprotectedDebugSocket.RunWithContext(ctx))
                }()
        }

        // spawn a new goroutine for closing the MuxAndDiscoveryComplete signal
        // registration happens during construction of the generic api server
        // the last server in the chain aggregates signals from the previous instances
        go func() {
                for _, muxAndDiscoveryCompletedSignal := range s.GenericAPIServer.MuxAndDiscoveryCompleteSignals() {
                        select {
                        case <-muxAndDiscoveryCompletedSignal:
                                continue
                        case <-stopCh:
                                klog.V(1).Infof("haven't completed %s, stop requested", s.lifecycleSignals.MuxAndDiscoveryComplete.Name())
                                return
                        }
                }
                s.lifecycleSignals.MuxAndDiscoveryComplete.Signal()
                klog.V(1).Infof("%s has all endpoints registered and discovery information is complete", s.lifecycleSignals.MuxAndDiscoveryComplete.Name())
        }()

        go func() {
                defer delayedStopCh.Signal()
                defer klog.V(1).InfoS("[graceful-termination] shutdown event", "name", delayedStopCh.Name())

                <-stopCh

                // As soon as shutdown is initiated, /readyz should start returning failure.
                // This gives the load balancer a window defined by ShutdownDelayDuration to detect that /readyz is red
                // and stop sending traffic to this server.
                shutdownInitiatedCh.Signal()
                klog.V(1).InfoS("[graceful-termination] shutdown event", "name", shutdownInitiatedCh.Name())

                time.Sleep(s.ShutdownDelayDuration)
        }()

        // close socket after delayed stopCh
        shutdownTimeout := s.ShutdownTimeout
        if s.ShutdownSendRetryAfter {
                // when this mode is enabled, we do the following:
                // - the server will continue to listen until all existing requests in flight
                //   (not including active long running requests) have been drained.
                // - once drained, http Server Shutdown is invoked with a timeout of 2s,
                //   net/http waits for 1s for the peer to respond to a GO_AWAY frame, so
                //   we should wait for a minimum of 2s
                shutdownTimeout = 2 * time.Second
                klog.V(1).InfoS("[graceful-termination] using HTTP Server shutdown timeout", "shutdownTimeout", shutdownTimeout)
        }

        notAcceptingNewRequestCh := s.lifecycleSignals.NotAcceptingNewRequest
        drainedCh := s.lifecycleSignals.InFlightRequestsDrained
        // Canceling the parent context does not immediately cancel the HTTP server.
        // We only inherit context values here and deal with cancellation ourselves.
        stopHTTPServerCtx, stopHTTPServer := context.WithCancelCause(context.WithoutCancel(ctx))
        go func() {
                defer stopHTTPServer(errors.New("time to stop HTTP server"))

                timeToStopHttpServerCh := notAcceptingNewRequestCh.Signaled()
                if s.ShutdownSendRetryAfter {
                        timeToStopHttpServerCh = drainedCh.Signaled()
                }

                <-timeToStopHttpServerCh
        }()

func (a *APIInstaller) Install() ([]metav1.APIResource, []*storageversion.ResourceInfo, *restful.WebService, []error) {
        var apiResources []metav1.APIResource
        var resourceInfos []*storageversion.ResourceInfo
        var errors []error
        ws := a.newWebService()

        // Register the paths in a deterministic (sorted) order to get a deterministic swagger spec.
        paths := make([]string, len(a.group.Storage))
        var i int = 0
        for path := range a.group.Storage {
                paths[i] = path
                i++
        }
        sort.Strings(paths)
        for _, path := range paths {
                apiResource, resourceInfo, err := a.registerResourceHandlers(path, a.group.Storage[path], ws)
                if err != nil {
                        errors = append(errors, fmt.Errorf("error in registering resource: %s, %v", path, err))
                }
                if apiResource != nil {
                        apiResources = append(apiResources, *apiResource)
                }
                if resourceInfo != nil {
                        resourceInfos = append(resourceInfos, resourceInfo)
                }
        }
        return apiResources, resourceInfos, ws, errors
}

// newWebService creates a new restful webservice with the api installer's prefix and version.
func (a *APIInstaller) newWebService() *restful.WebService {
        ws := new(restful.WebService)
        ws.Path(a.prefix)
        // a.prefix contains "prefix/group/version"
        ws.Doc("API at " + a.prefix)
        // Backwards compatibility, we accepted objects with empty content-type at V1.
        // If we stop using go-restful, we can default empty content-type to application/json on an
        // endpoint by endpoint basis
        ws.Consumes("*/*")
        mediaTypes, streamMediaTypes := negotiation.MediaTypesForSerializer(a.group.Serializer)
        ws.Produces(append(mediaTypes, streamMediaTypes...)...)
        ws.ApiVersion(a.group.GroupVersion.String())

        return ws
}

// calculate the storage gvk, the gvk objects are converted to before persisted to the etcd.
func getStorageVersionKind(storageVersioner runtime.GroupVersioner, storage rest.Storage, typer runtime.ObjectTyper) (schema.GroupVersionKind, error) {
        object := storage.New()
        fqKinds, _, err := typer.ObjectKinds(object)
        if err != nil {
                return schema.GroupVersionKind{}, err
        }
        gvk, ok := storageVersioner.KindForGroupVersionKinds(fqKinds)
        if !ok {
                return schema.GroupVersionKind{}, fmt.Errorf("cannot find the storage version kind for %v", reflect.TypeOf(object))
        }
        return gvk, nil
}

// GetResourceKind returns the external group version kind registered for the given storage
// object. If the storage object is a subresource and has an override supplied for it, it returns
// the group version kind supplied in the override.
func GetResourceKind(groupVersion schema.GroupVersion, storage rest.Storage, typer runtime.ObjectTyper) (schema.GroupVersionKind, error) {
        // Let the storage tell us exactly what GVK it has
        if gvkProvider, ok := storage.(rest.GroupVersionKindProvider); ok {
                return gvkProvider.GroupVersionKind(groupVersion), nil
        }

        object := storage.New()
        fqKinds, _, err := typer.ObjectKinds(object)
        if err != nil {
                return schema.GroupVersionKind{}, err
        }

        // a given go type can have multiple potential fully qualified kinds.  Find the one that corresponds with the group
        // we're trying to register here
        fqKindToRegister := schema.GroupVersionKind{}
        for _, fqKind := range fqKinds {
                if fqKind.Group == groupVersion.Group {
                        fqKindToRegister = groupVersion.WithKind(fqKind.Kind)
                        break
                }
        }
        if fqKindToRegister.Empty() {
                return schema.GroupVersionKind{}, fmt.Errorf("unable to locate fully qualified kind for %v: found %v when registering for %v", reflect.TypeOf(object), fqKinds, groupVersion)
        }

        // group is guaranteed to match based on the check above
        return fqKindToRegister, nil
}

func (a *APIInstaller) registerResourceHandlers(path string, storage rest.Storage, ws *restful.WebService) (*metav1.APIResource, *storageversion.ResourceInfo, error) {
        admit := a.group.Admit

        optionsExternalVersion := a.group.GroupVersion
        if a.group.OptionsExternalVersion != nil {
                optionsExternalVersion = *a.group.OptionsExternalVersion
        }

        resource, subresource, err := splitSubresource(path)
        if err != nil {
                return nil, nil, err
        }

        group, version := a.group.GroupVersion.Group, a.group.GroupVersion.Version

        fqKindToRegister, err := GetResourceKind(a.group.GroupVersion, storage, a.group.Typer)
        if err != nil {
                return nil, nil, err
        }

        versionedPtr, err := a.group.Creater.New(fqKindToRegister)
        if err != nil {
                return nil, nil, err
        }
        defaultVersionedObject := indirectArbitraryPointer(versionedPtr)
        kind := fqKindToRegister.Kind
        isSubresource := len(subresource) > 0

        // If there is a subresource, namespace scoping is defined by the parent resource
        var namespaceScoped bool
        if isSubresource {
                parentStorage, ok := a.group.Storage[resource]
                if !ok {
                        return nil, nil, fmt.Errorf("missing parent storage: %q", resource)
                }
                scoper, ok := parentStorage.(rest.Scoper)
                if !ok {
                        return nil, nil, fmt.Errorf("%q must implement scoper", resource)
                }
                namespaceScoped = scoper.NamespaceScoped()

        } else {
                scoper, ok := storage.(rest.Scoper)
                if !ok {
                        return nil, nil, fmt.Errorf("%q must implement scoper", resource)
                }
                namespaceScoped = scoper.NamespaceScoped()
        }

        // what verbs are supported by the storage, used to know what verbs we support per path
        creater, isCreater := storage.(rest.Creater)
        namedCreater, isNamedCreater := storage.(rest.NamedCreater)
        lister, isLister := storage.(rest.Lister)
        getter, isGetter := storage.(rest.Getter)
        getterWithOptions, isGetterWithOptions := storage.(rest.GetterWithOptions)
        gracefulDeleter, isGracefulDeleter := storage.(rest.GracefulDeleter)
        collectionDeleter, isCollectionDeleter := storage.(rest.CollectionDeleter)
        updater, isUpdater := storage.(rest.Updater)
        patcher, isPatcher := storage.(rest.Patcher)
        watcher, isWatcher := storage.(rest.Watcher)
        connecter, isConnecter := storage.(rest.Connecter)
        storageMeta, isMetadata := storage.(rest.StorageMetadata)
        storageVersionProvider, isStorageVersionProvider := storage.(rest.StorageVersionProvider)
        gvAcceptor, _ := storage.(rest.GroupVersionAcceptor)

gvAcceptor, _ := storage.(rest.GroupVersionAcceptor)
        if !isMetadata {
                storageMeta = defaultStorageMetadata{}
        }

        if isNamedCreater {
                isCreater = true
        }

        var versionedList interface{}
        if isLister {
                list := lister.NewList()
                listGVKs, _, err := a.group.Typer.ObjectKinds(list)
                if err != nil {
                        return nil, nil, err
                }
                versionedListPtr, err := a.group.Creater.New(a.group.GroupVersion.WithKind(listGVKs[0].Kind))
                if err != nil {
                        return nil, nil, err
                }
                versionedList = indirectArbitraryPointer(versionedListPtr)
        }

        versionedListOptions, err := a.group.Creater.New(optionsExternalVersion.WithKind("ListOptions"))
        if err != nil {
                return nil, nil, err
        }
        versionedCreateOptions, err := a.group.Creater.New(optionsExternalVersion.WithKind("CreateOptions"))
        if err != nil {
                return nil, nil, err
        }
        versionedPatchOptions, err := a.group.Creater.New(optionsExternalVersion.WithKind("PatchOptions"))
        if err != nil {
                return nil, nil, err
        }
        versionedUpdateOptions, err := a.group.Creater.New(optionsExternalVersion.WithKind("UpdateOptions"))
        if err != nil {
                return nil, nil, err
        }

        var versionedDeleteOptions runtime.Object
        var versionedDeleterObject interface{}
        deleteReturnsDeletedObject := false
        if isGracefulDeleter {
                versionedDeleteOptions, err = a.group.Creater.New(optionsExternalVersion.WithKind("DeleteOptions"))
                if err != nil {
                        return nil, nil, err
                }
                versionedDeleterObject = indirectArbitraryPointer(versionedDeleteOptions)

                if mayReturnFullObjectDeleter, ok := storage.(rest.MayReturnFullObjectDeleter); ok {
                        deleteReturnsDeletedObject = mayReturnFullObjectDeleter.DeleteReturnsDeletedObject()
                }
        }

        versionedStatusPtr, err := a.group.Creater.New(optionsExternalVersion.WithKind("Status"))
        if err != nil {
                return nil, nil, err
        }
        versionedStatus := indirectArbitraryPointer(versionedStatusPtr)
        var (
                getOptions             runtime.Object
                versionedGetOptions    runtime.Object
                getOptionsInternalKind schema.GroupVersionKind
                getSubpath             bool
        )
        if isGetterWithOptions {
                getOptions, getSubpath, _ = getterWithOptions.NewGetOptions()
                getOptionsInternalKinds, _, err := a.group.Typer.ObjectKinds(getOptions)
                if err != nil {
                        return nil, nil, err
                }
                getOptionsInternalKind = getOptionsInternalKinds[0]
                versionedGetOptions, err = a.group.Creater.New(a.group.GroupVersion.WithKind(getOptionsInternalKind.Kind))
