func (c *Cacher) Watch(ctx context.Context, key string, opts storage.ListOptions) (watch.Interface, error) {
        key, err := c.prepareKey(key, opts.Recursive)
        if err != nil {
                return nil, err
        }
        pred := opts.Predicate
        requestedWatchRV, err := c.versioner.ParseResourceVersion(opts.ResourceVersion)
        if err != nil {
                return nil, err
        }

        var readyGeneration int
        if utilfeature.DefaultFeatureGate.Enabled(features.ResilientWatchCacheInitialization) {
                var err error
                var downtime time.Duration
                readyGeneration, downtime, err = c.ready.checkAndReadGeneration()
                if err != nil {
                        return nil, errors.NewTooManyRequests(err.Error(), calculateRetryAfterForUnreadyCache(downtime))
                }
        } else {
                readyGeneration, err = c.ready.waitAndReadGeneration(ctx)
                if err != nil {
                        return nil, errors.NewServiceUnavailable(err.Error())
                }
        }

        // determine the namespace and name scope of the watch, first from the request, secondarily from the field selector
        scope := namespacedName{}
        if requestNamespace, ok := request.NamespaceFrom(ctx); ok && len(requestNamespace) > 0 {
                scope.namespace = requestNamespace
        } else if selectorNamespace, ok := pred.Field.RequiresExactMatch("metadata.namespace"); ok {
                scope.namespace = selectorNamespace
        }
        if requestInfo, ok := request.RequestInfoFrom(ctx); ok && requestInfo != nil && len(requestInfo.Name) > 0 {
                scope.name = requestInfo.Name
        } else if selectorName, ok := pred.Field.RequiresExactMatch("metadata.name"); ok {
                scope.name = selectorName
        }

        // for request like '/api/v1/watch/namespaces/*', set scope.namespace to empty.
        // namespaces don't populate metadata.namespace in ObjFields.
        if c.groupResource == coreNamespaceResource && len(scope.namespace) > 0 && scope.namespace == scope.name {
                scope.namespace = ""
        }

        triggerValue, triggerSupported := "", false
        if c.indexedTrigger != nil {
                for _, field := range pred.IndexFields {
                        if field == c.indexedTrigger.indexName {
                                if value, ok := pred.Field.RequiresExactMatch(field); ok {
                                        triggerValue, triggerSupported = value, true
                                        break
                                }
                        }
                }
        }

        // It boils down to a tradeoff between:
        // - having it as small as possible to reduce memory usage
        // - having it large enough to ensure that watchers that need to process
        //   a bunch of changes have enough buffer to avoid from blocking other
        //   watchers on our watcher having a processing hiccup
        chanSize := c.watchCache.suggestedWatchChannelSize(c.indexedTrigger != nil, triggerSupported)

        // client-go is going to fall back to a standard LIST on any error
        // returned for watch-list requests
        if isListWatchRequest(opts) && !etcdfeature.DefaultFeatureSupportChecker.Supports(storage.RequestWatchProgress) {
                return newErrWatcher(fmt.Errorf("a watch stream was requested by the client but the required storage feature %s is disabled", storage.RequestWatchProgress)), nil
        }

        // Determine the ResourceVersion to which the watch cache must be synchronized
        requiredResourceVersion, err := c.getWatchCacheResourceVersion(ctx, requestedWatchRV, opts)
        if err != nil {
                return newErrWatcher(err), nil
        }

        // Determine a function that computes the bookmarkAfterResourceVersion
        bookmarkAfterResourceVersionFn, err := c.getBookmarkAfterResourceVersionLockedFunc(requestedWatchRV, requiredResourceVersion, opts)
        if err != nil {
                return newErrWatcher(err), nil
        }

        // Determine watch timeout('0' means deadline is not set, ignore checking)
        deadline, _ := ctx.Deadline()

        identifier := fmt.Sprintf("key: %q, labels: %q, fields: %q", key, pred.Label, pred.Field)

        // Create a watcher here to reduce memory allocations under lock,
        // given that memory allocation may trigger GC and block the thread.
        // Also note that emptyFunc is a placeholder, until we will be able
        // to compute watcher.forget function (which has to happen under lock).
        watcher := newCacheWatcher(
                chanSize,
                filterWithAttrsAndPrefixFunction(key, pred),
                emptyFunc,
                c.versioner,
                deadline,
                pred.AllowWatchBookmarks,
                c.groupResource,
                identifier,
        )

        // note that c.waitUntilWatchCacheFreshAndForceAllEvents must be called without
        // the c.watchCache.RLock held otherwise we are at risk of a deadlock
        // mainly because c.watchCache.processEvent method won't be able to make progress
        //
        // moreover even though the c.waitUntilWatchCacheFreshAndForceAllEvents acquires a lock
        // it is safe to release the lock after the method finishes because we don't require
        // any atomicity between the call to the method and further calls that actually get the events.
        err = c.waitUntilWatchCacheFreshAndForceAllEvents(ctx, requiredResourceVersion, opts)
        if err != nil {
                return newErrWatcher(err), nil
        }

// resourceVersionTooHighRetrySeconds is the seconds before a operation should be retried by the client
        // after receiving a 'too high resource version' error.
        resourceVersionTooHighRetrySeconds = 1

        // defaultLowerBoundCapacity is a default value for event cache capacity's lower bound.
        // TODO: Figure out, to what value we can decreased it.
        defaultLowerBoundCapacity = 100

        // defaultUpperBoundCapacity should be able to keep the required history.
        defaultUpperBoundCapacity = 100 * 1024
)

// watchCacheEvent is a single "watch event" that is send to users of
// watchCache. Additionally to a typical "watch.Event" it contains
// the previous value of the object to enable proper filtering in the
// upper layers.
type watchCacheEvent struct {
        Type            watch.EventType
        Object          runtime.Object
        ObjLabels       labels.Set
        ObjFields       fields.Set
        PrevObject      runtime.Object
        PrevObjLabels   labels.Set
        PrevObjFields   fields.Set
        Key             string
        ResourceVersion uint64
        RecordTime      time.Time
}

// watchCache implements a Store interface.
// However, it depends on the elements implementing runtime.Object interface.
//
// watchCache is a "sliding window" (with a limited capacity) of objects
// observed from a watch.
type watchCache struct {
        sync.RWMutex

        // Condition on which lists are waiting for the fresh enough
        // resource version.
        cond *sync.Cond

        // Maximum size of history window.
        capacity int

        // upper bound of capacity since event cache has a dynamic size.
        upperBoundCapacity int

func (s *GenericAPIServer) PrepareRun() preparedGenericAPIServer {
        s.delegationTarget.PrepareRun()

        if s.openAPIConfig != nil && !s.skipOpenAPIInstallation {
                s.OpenAPIVersionedService, s.StaticOpenAPISpec = routes.OpenAPI{
                        Config: s.openAPIConfig,
                }.InstallV2(s.Handler.GoRestfulContainer, s.Handler.NonGoRestfulMux)
        }

        if s.openAPIV3Config != nil && !s.skipOpenAPIInstallation {
                s.OpenAPIV3VersionedService = routes.OpenAPI{
                        V3Config: s.openAPIV3Config,
                }.InstallV3(s.Handler.GoRestfulContainer, s.Handler.NonGoRestfulMux)
        }

        s.installHealthz()
        s.installLivez()

        // as soon as shutdown is initiated, readiness should start failing
        readinessStopCh := s.lifecycleSignals.ShutdownInitiated.Signaled()
        err := s.addReadyzShutdownCheck(readinessStopCh)
        if err != nil {
                klog.Errorf("Failed to install readyz shutdown check %s", err)
        }
        s.installReadyz()

        if utilfeature.DefaultFeatureGate.Enabled(zpagesfeatures.ComponentStatusz) {
                statusz.Install(s.Handler.NonGoRestfulMux, "apiserver", statusz.NewRegistry(s.EffectiveVersion, statusz.WithListedPaths(s.ListedPaths())))
        }

        return preparedGenericAPIServer{s}
}

// Run spawns the secure http server. It only returns if stopCh is closed
// or the secure port cannot be listened on initially.
//
// Deprecated: use RunWithContext instead. Run will not get removed to avoid
// breaking consumers, but should not be used in new code.
func (s preparedGenericAPIServer) Run(stopCh <-chan struct{}) error {
        ctx := wait.ContextForChannel(stopCh)
        return s.RunWithContext(ctx)
}

// RunWithContext spawns the secure http server. It only returns if ctx is canceled
// or the secure port cannot be listened on initially.
// This is the diagram of what contexts/channels/signals are dependent on each other:
//
// |                                   ctx
// |                                    |
// |           ---------------------------------------------------------
// |           |                                                       |
// |    ShutdownInitiated (shutdownInitiatedCh)                        |
// |           |                                                       |
// | (ShutdownDelayDuration)                                    (PreShutdownHooks)
// |           |                                                       |
// |  AfterShutdownDelayDuration (delayedStopCh)   PreShutdownHooksStopped (preShutdownHooksHasStoppedCh)
// |           |                                                       |
// |           |-------------------------------------------------------|
// |                                    |
// |                                    |
// |               NotAcceptingNewRequest (notAcceptingNewRequestCh)
// |                                    |
// |                                    |
// |           |----------------------------------------------------------------------------------|
// |           |                        |              |                                          |
// |        [without                 [with             |                                          |
// | ShutdownSendRetryAfter]  ShutdownSendRetryAfter]  |                                          |
// |           |                        |              |                                          |
// |           |                        ---------------|                                          |
// |           |                                       |                                          |
// |           |                      |----------------|-----------------------|                  |
// |           |                      |                                        |                  |
// |           |         (NonLongRunningRequestWaitGroup::Wait)   (WatchRequestWaitGroup::Wait)   |
// |           |                      |                                        |                  |
// |           |                      |------------------|---------------------|                  |
// |           |                                         |                                        |
// |           |                         InFlightRequestsDrained (drainedCh)                      |
// |           |                                         |                                        |
// |           |-------------------|---------------------|----------------------------------------|
// |                               |                     |
// |                       stopHttpServerCtx     (AuditBackend::Shutdown())
// |                               |
// |                       listenerStoppedCh
// |                               |
// |      HTTPServerStoppedListening (httpServerStoppedListeningCh)
func (s preparedGenericAPIServer) RunWithContext(ctx context.Context) error {
        stopCh := ctx.Done()
        delayedStopCh := s.lifecycleSignals.AfterShutdownDelayDuration
        shutdownInitiatedCh := s.lifecycleSignals.ShutdownInitiated

        // Clean up resources on shutdown.
        defer s.Destroy()

        // If UDS profiling is enabled, start a local http server listening on that socket
        if s.UnprotectedDebugSocket != nil {
                go func() {
                        defer utilruntime.HandleCrashWithContext(ctx)
                        klog.Error(s.UnprotectedDebugSocket.RunWithContext(ctx))
                }()
        }

// spawn a new goroutine for closing the MuxAndDiscoveryComplete signal
        // registration happens during construction of the generic api server
        // the last server in the chain aggregates signals from the previous instances
        go func() {
                for _, muxAndDiscoveryCompletedSignal := range s.GenericAPIServer.MuxAndDiscoveryCompleteSignals() {
                        select {
                        case <-muxAndDiscoveryCompletedSignal:
                                continue
                        case <-stopCh:
                                klog.V(1).Infof("haven't completed %s, stop requested", s.lifecycleSignals.MuxAndDiscoveryComplete.Name())
                                return
                        }
                }
                s.lifecycleSignals.MuxAndDiscoveryComplete.Signal()
                klog.V(1).Infof("%s has all endpoints registered and discovery information is complete", s.lifecycleSignals.MuxAndDiscoveryComplete.Name())
        }()

        go func() {
                defer delayedStopCh.Signal()
                defer klog.V(1).InfoS("[graceful-termination] shutdown event", "name", delayedStopCh.Name())

                <-stopCh

                // As soon as shutdown is initiated, /readyz should start returning failure.
                // This gives the load balancer a window defined by ShutdownDelayDuration to detect that /readyz is red
                // and stop sending traffic to this server.
                shutdownInitiatedCh.Signal()
                klog.V(1).InfoS("[graceful-termination] shutdown event", "name", shutdownInitiatedCh.Name())

                time.Sleep(s.ShutdownDelayDuration)
        }()

        // close socket after delayed stopCh
        shutdownTimeout := s.ShutdownTimeout
        if s.ShutdownSendRetryAfter {
                // when this mode is enabled, we do the following:
                // - the server will continue to listen until all existing requests in flight
                //   (not including active long running requests) have been drained.
                // - once drained, http Server Shutdown is invoked with a timeout of 2s,
                //   net/http waits for 1s for the peer to respond to a GO_AWAY frame, so
                //   we should wait for a minimum of 2s
                shutdownTimeout = 2 * time.Second
                klog.V(1).InfoS("[graceful-termination] using HTTP Server shutdown timeout", "shutdownTimeout", shutdownTimeout)
        }

        notAcceptingNewRequestCh := s.lifecycleSignals.NotAcceptingNewRequest
        drainedCh := s.lifecycleSignals.InFlightRequestsDrained
        // Canceling the parent context does not immediately cancel the HTTP server.
        // We only inherit context values here and deal with cancellation ourselves.
        stopHTTPServerCtx, stopHTTPServer := context.WithCancelCause(context.WithoutCancel(ctx))
        go func() {
                defer stopHTTPServer(errors.New("time to stop HTTP server"))

                timeToStopHttpServerCh := notAcceptingNewRequestCh.Signaled()
                if s.ShutdownSendRetryAfter {
                        timeToStopHttpServerCh = drainedCh.Signaled()
                }

                <-timeToStopHttpServerCh
        }()

        // Start the audit backend before any request comes in. This means we must call Backend.Run
        // before http server start serving. Otherwise the Backend.ProcessEvents call might block.
        // AuditBackend.Run will stop as soon as all in-flight requests are drained.
        if s.AuditBackend != nil {
                if err := s.AuditBackend.Run(drainedCh.Signaled()); err != nil {
                        return fmt.Errorf("failed to run the audit backend: %v", err)
                }
        }

        stoppedCh, listenerStoppedCh, err := s.NonBlockingRunWithContext(stopHTTPServerCtx, shutdownTimeout)
        if err != nil {
                return err
        }

        httpServerStoppedListeningCh := s.lifecycleSignals.HTTPServerStoppedListening
        go func() {
                <-listenerStoppedCh
                httpServerStoppedListeningCh.Signal()
                klog.V(1).InfoS("[graceful-termination] shutdown event", "name", httpServerStoppedListeningCh.Name())
        }()

        // we don't accept new request as soon as both ShutdownDelayDuration has
        // elapsed and preshutdown hooks have completed.
        preShutdownHooksHasStoppedCh := s.lifecycleSignals.PreShutdownHooksStopped
        go func() {
                defer klog.V(1).InfoS("[graceful-termination] shutdown event", "name", notAcceptingNewRequestCh.Name())
                defer notAcceptingNewRequestCh.Signal()

                // wait for the delayed stopCh before closing the handler chain
                <-delayedStopCh.Signaled()

                // Additionally wait for preshutdown hooks to also be finished, as some of them need
                // to send API calls to clean up after themselves (e.g. lease reconcilers removing
                // itself from the active servers).
                <-preShutdownHooksHasStoppedCh.Signaled()
        }()

        // wait for all in-flight non-long running requests to finish
        nonLongRunningRequestDrainedCh := make(chan struct{})

