func CreateServerChain(config CompletedConfig) (*aggregatorapiserver.APIAggregator, error) {
        notFoundHandler := notfoundhandler.New(config.KubeAPIs.ControlPlane.Generic.Serializer, genericapifilters.NoMuxAndDiscoveryIncompleteKey)
        apiExtensionsServer, err := config.ApiExtensions.New(genericapiserver.NewEmptyDelegateWithCustomHandler(notFoundHandler))
        if err != nil {
                return nil, err
        }
        crdAPIEnabled := config.ApiExtensions.GenericConfig.MergedResourceConfig.ResourceEnabled(apiextensionsv1.SchemeGroupVersion.WithResource("customresourcedefinitions"))

        kubeAPIServer, err := config.KubeAPIs.New(apiExtensionsServer.GenericAPIServer)
        if err != nil {
                return nil, err
        }

        // aggregator comes last in the chain
        aggregatorServer, err := controlplaneapiserver.CreateAggregatorServer(config.Aggregator, kubeAPIServer.ControlPlane.GenericAPIServer, apiExtensionsServer.Informers.Apiextensions().V1().CustomResourceDefinitions(), crdAPIEnabled, apiVersionPriorities)
        if err != nil {
                // we don't need special handling for innerStopCh because the aggregator server doesn't create any go routines
                return nil, err
        }

        return aggregatorServer, nil
}

// CreateKubeAPIServerConfig creates all the resources for running the API server, but runs none of them
func CreateKubeAPIServerConfig(
        opts options.CompletedOptions,
        genericConfig *genericapiserver.Config,
        versionedInformers clientgoinformers.SharedInformerFactory,
        storageFactory *serverstorage.DefaultStorageFactory,
) (
        *controlplane.Config,
        aggregatorapiserver.ServiceResolver,
        []admission.PluginInitializer,
        error,
) {
        // global stuff
        capabilities.Setup(opts.AllowPrivileged, opts.MaxConnectionBytesPerSec)

        // additional admission initializers
        kubeAdmissionConfig := &kubeapiserveradmission.Config{}
        kubeInitializers, err := kubeAdmissionConfig.New()
        if err != nil {
                return nil, nil, nil, fmt.Errorf("failed to create admission plugin initializer: %w", err)
        }

        serviceResolver, err := buildServiceResolver(opts.EnableAggregatorRouting, genericConfig.LoopbackClientConfig.Host, versionedInformers)
        if err != nil {
                return nil, nil, nil, fmt.Errorf("error building service resolver: %w", err)
        }
        controlplaneConfig, admissionInitializers, err := controlplaneapiserver.CreateConfig(opts.CompletedOptions, genericConfig, versionedInformers, storageFactory, serviceResolver, kubeInitializers)
        if err != nil {
                return nil, nil, nil, err
        }

        config := &controlplane.Config{
                ControlPlane: *controlplaneConfig,
                Extra: controlplane.Extra{
                        KubeletClientConfig: opts.KubeletConfig,

                        ServiceIPRange:          opts.PrimaryServiceClusterIPRange,
                        APIServerServiceIP:      opts.APIServerServiceIP,
                        SecondaryServiceIPRange: opts.SecondaryServiceClusterIPRange,

                        APIServerServicePort: 443,

                        ServiceNodePortRange:      opts.ServiceNodePortRange,
                        KubernetesServiceNodePort: opts.KubernetesServiceNodePort,

                        EndpointReconcilerType: reconcilers.Type(opts.EndpointReconcilerType),
                        MasterCount:            opts.MasterCount,
                },
        }

        if config.ControlPlane.Generic.EgressSelector != nil {
                // Use the config.ControlPlane.Generic.EgressSelector lookup to find the dialer to connect to the kubelet
                config.Extra.KubeletClientConfig.Lookup = config.ControlPlane.Generic.EgressSelector.Lookup

                // Use the config.ControlPlane.Generic.EgressSelector lookup as the transport used by the "proxy" subresources.
                networkContext := egressselector.Cluster.AsNetworkContext()
                dialer, err := config.ControlPlane.Generic.EgressSelector.Lookup(networkContext)
                if err != nil {
                        return nil, nil, nil, err
                }
                c := config.ControlPlane.Extra.ProxyTransport.Clone()
                c.DialContext = dialer
                config.ControlPlane.ProxyTransport = c
        }

        return config, serviceResolver, admissionInitializers, nil
}

var testServiceResolver webhook.ServiceResolver

// SetServiceResolverForTests allows the service resolver to be overridden during tests.
// Tests using this function must run serially as this function is not safe to call concurrently with server start.
func SetServiceResolverForTests(resolver webhook.ServiceResolver) func() {
        if testServiceResolver != nil {
                panic("test service resolver is set: tests are either running concurrently or clean up was skipped")
        }

        testServiceResolver = resolver

        return func() {
                testServiceResolver = nil
        }
}

func buildServiceResolver(enabledAggregatorRouting bool, hostname string, informer clientgoinformers.SharedInformerFactory) (webhook.ServiceResolver, error) {
        if testServiceResolver != nil {
                return testServiceResolver, nil
        }

        endpointSliceGetter, err := proxy.NewEndpointSliceIndexerGetter(informer.Discovery().V1().EndpointSlices())
        if err != nil {
                return nil, err
        }

        var serviceResolver webhook.ServiceResolver
        if enabledAggregatorRouting {
                serviceResolver = aggregatorapiserver.NewEndpointServiceResolver(
                        informer.Core().V1().Services().Lister(),
                        endpointSliceGetter,
                )
        } else {
                serviceResolver = aggregatorapiserver.NewClusterIPServiceResolver(
                        informer.Core().V1().Services().Lister(),
                )
        }

        // resolve kubernetes.default.svc locally
        if localHost, err := url.Parse(hostname); err == nil {
                serviceResolver = aggregatorapiserver.NewLoopbackServiceResolver(serviceResolver, localHost)
        }
        return serviceResolver, nil
}

func (s *store) GuaranteedUpdate(
        ctx context.Context, key string, destination runtime.Object, ignoreNotFound bool,
        preconditions *storage.Preconditions, tryUpdate storage.UpdateFunc, cachedExistingObject runtime.Object) error {
        preparedKey, err := s.prepareKey(key, false)
        if err != nil {
                return err
        }
        ctx, span := tracing.Start(ctx, "GuaranteedUpdate etcd3",
                attribute.String("audit-id", audit.GetAuditIDTruncated(ctx)),
                attribute.String("key", key),
                attribute.String("type", getTypeName(destination)),
                attribute.String("group", s.groupResource.Group),
                attribute.String("resource", s.groupResource.Resource))
        defer span.End(500 * time.Millisecond)

        v, err := conversion.EnforcePtr(destination)
        if err != nil {
                return fmt.Errorf("unable to convert output object to pointer: %v", err)
        }

        skipTransformDecode := false
        getCurrentState := s.getCurrentState(ctx, preparedKey, v, ignoreNotFound, skipTransformDecode)

        var origState *objState
        var origStateIsCurrent bool
        if cachedExistingObject != nil {
                origState, err = s.getStateFromObject(cachedExistingObject)
        } else {
                origState, err = getCurrentState()
                origStateIsCurrent = true
        }
        if err != nil {
                return err
        }
        span.AddEvent("initial value restored")

        transformContext := authenticatedDataString(preparedKey)
        for {
                if err := preconditions.Check(preparedKey, origState.obj); err != nil {
                        // If our data is already up to date, return the error
                        if origStateIsCurrent {
                                return err
                        }

                        // It's possible we were working with stale data
                        // Actually fetch
                        origState, err = getCurrentState()
                        if err != nil {
                                return err
                        }
                        origStateIsCurrent = true
                        // Retry
                        continue
                }

                ret, ttl, err := s.updateState(origState, tryUpdate)
                if err != nil {
                        // If our data is already up to date, return the error
                        if origStateIsCurrent {
                                return err
                        }

                        // It's possible we were working with stale data
                        // Remember the revision of the potentially stale data and the resulting update error
                        cachedRev := origState.rev
                        cachedUpdateErr := err

                        // Actually fetch
                        origState, err = getCurrentState()
                        if err != nil {
                                return err
                        }
                        origStateIsCurrent = true

                        // it turns out our cached data was not stale, return the error
                        if cachedRev == origState.rev {
                                return cachedUpdateErr
                        }

                        // Retry
                        continue
                }

                span.AddEvent("About to Encode")
                data, err := runtime.Encode(s.codec, ret)
                if err != nil {
                        span.AddEvent("Encode failed", attribute.Int("len", len(data)), attribute.String("err", err.Error()))
                        return err
                }
                span.AddEvent("Encode succeeded", attribute.Int("len", len(data)))
                if !origState.stale && bytes.Equal(data, origState.data) {
                        // if we skipped the original Get in this loop, we must refresh from
                        // etcd in order to be sure the data in the store is equivalent to
                        // our desired serialization
                        if !origStateIsCurrent {
                                origState, err = getCurrentState()
                                if err != nil {
                                        return err
                                }
                                origStateIsCurrent = true
                                if !bytes.Equal(data, origState.data) {
                                        // original data changed, restart loop
                                        continue
                                }
                        }
                        // recheck that the data from etcd is not stale before short-circuiting a write
                        if !origState.stale {
                                err = s.decoder.Decode(origState.data, destination, origState.rev)
                                if err != nil {
                                        recordDecodeError(s.groupResource, preparedKey)
                                        return err
                                }
                                return nil
                        }
                }

                newData, err := s.transformer.TransformToStorage(ctx, data, transformContext)
                if err != nil {
                        span.AddEvent("TransformToStorage failed", attribute.String("err", err.Error()))
                        return storage.NewInternalError(err)
                }
                span.AddEvent("TransformToStorage succeeded")

                var lease clientv3.LeaseID
                if ttl != 0 {
                        lease, err = s.leaseManager.GetLease(ctx, int64(ttl))
                        if err != nil {
                                return err
                        }
                }
                span.AddEvent("Transaction prepared")

                startTime := time.Now()

                txnResp, err := s.client.Kubernetes.OptimisticPut(ctx, preparedKey, newData, origState.rev, kubernetes.PutOptions{
                        GetOnFailure: true,
                        LeaseID:      lease,
                })

func (e *Store) create(ctx context.Context, obj runtime.Object, createValidation rest.ValidateObjectFunc, options *metav1.CreateOptions) (runtime.Object, error) {
        var finishCreate FinishFunc = finishNothing

        // Init metadata as early as possible.
        if objectMeta, err := meta.Accessor(obj); err != nil {
                return nil, err
        } else {
                rest.FillObjectMetaSystemFields(objectMeta)
                if len(objectMeta.GetGenerateName()) > 0 && len(objectMeta.GetName()) == 0 {
                        objectMeta.SetName(e.CreateStrategy.GenerateName(objectMeta.GetGenerateName()))
                }
        }

        if e.BeginCreate != nil {
                fn, err := e.BeginCreate(ctx, obj, options)
                if err != nil {
                        return nil, err
                }
                finishCreate = fn
                defer func() {
                        finishCreate(ctx, false)
                }()
        }

        if err := rest.BeforeCreate(e.CreateStrategy, ctx, obj); err != nil {
                return nil, err
        }
        // at this point we have a fully formed object.  It is time to call the validators that the apiserver
        // handling chain wants to enforce.
        if createValidation != nil {
                if err := createValidation(ctx, obj.DeepCopyObject()); err != nil {
                        return nil, err
                }
        }

        name, err := e.ObjectNameFunc(obj)
        if err != nil {
                return nil, err
        }
        key, err := e.KeyFunc(ctx, name)
        if err != nil {
                return nil, err
        }
        qualifiedResource := e.qualifiedResourceFromContext(ctx)
        ttl, err := e.calculateTTL(obj, 0, false)
        if err != nil {
                return nil, err
        }
        out := e.NewFunc()
        if err := e.Storage.Create(ctx, key, obj, out, ttl, dryrun.IsDryRun(options.DryRun)); err != nil {
                err = storeerr.InterpretCreateError(err, qualifiedResource, name)
                err = rest.CheckGeneratedNameError(ctx, e.CreateStrategy, err, obj)
                if !apierrors.IsAlreadyExists(err) {
                        return nil, err
                }
                if errGet := e.Storage.Get(ctx, key, storage.GetOptions{}, out); errGet != nil {
                        return nil, err
                }
                accessor, errGetAcc := meta.Accessor(out)
                if errGetAcc != nil {
                        return nil, err
                }
                if accessor.GetDeletionTimestamp() != nil {
                        msg := &err.(*apierrors.StatusError).ErrStatus.Message
                        *msg = fmt.Sprintf("object is being deleted: %s", *msg)
                }
                return nil, err
        }
        // The operation has succeeded.  Call the finish function if there is one,
        // and then make sure the defer doesn't call it again.
        fn := finishCreate
        finishCreate = finishNothing
        fn(ctx, true)

        if e.AfterCreate != nil {
                e.AfterCreate(out, options)
        }
        if e.Decorator != nil {
                e.Decorator(out)
        }
        return out, nil
}

// ShouldDeleteDuringUpdate is the default function for
// checking if an object should be deleted during an update.
// It checks if the new object has no finalizers,
// the existing object's deletionTimestamp is set, and
// the existing object's deletionGracePeriodSeconds is 0 or nil
func ShouldDeleteDuringUpdate(ctx context.Context, key string, obj, existing runtime.Object) bool {
        newMeta, err := meta.Accessor(obj)
        if err != nil {
                utilruntime.HandleError(err)
                return false
        }
        oldMeta, err := meta.Accessor(existing)
        if err != nil {
                utilruntime.HandleError(err)
                return false
        }
        if len(newMeta.GetFinalizers()) > 0 {
                // don't delete with finalizers remaining in the new object
                return false
        }
        if oldMeta.GetDeletionTimestamp() == nil {
                // don't delete if the existing object hasn't had a delete request made
                return false
        }
        // delete if the existing object has no grace period or a grace period of 0
        return oldMeta.GetDeletionGracePeriodSeconds() == nil || *oldMeta.GetDeletionGracePeriodSeconds() == 0
}

// deleteWithoutFinalizers handles deleting an object ignoring its finalizer list.
// Used for objects that are either been finalized or have never initialized.
func (e *Store) deleteWithoutFinalizers(ctx context.Context, name, key string, obj runtime.Object, preconditions *storage.Preconditions, options *metav1.DeleteOptions) (runtime.Object, bool, error) {
        out := e.NewFunc()
        klog.V(6).InfoS("Going to delete object from registry, triggered by update", "object", klog.KRef(genericapirequest.NamespaceValue(ctx), name))
        // Using the rest.ValidateAllObjectFunc because the request is an UPDATE request and has already passed the admission for the UPDATE verb.
        if err := e.Storage.Delete(ctx, key, out, preconditions, rest.ValidateAllObjectFunc, dryrun.IsDryRun(options.DryRun), nil, storage.DeleteOptions{}); err != nil {
                // Deletion is racy, i.e., there could be multiple update
                // requests to remove all finalizers from the object, so we
                // ignore the NotFound error.
                if storage.IsNotFound(err) {
                        _, err := e.finalizeDelete(ctx, obj, true, options)
                        // clients are expecting an updated object if a PUT succeeded,
                        // but finalizeDelete returns a metav1.Status, so return
                        // the object in the request instead.
                        return obj, false, err
                }
                return nil, false, storeerr.InterpretDeleteError(err, e.qualifiedResourceFromContext(ctx), name)
        }
        _, err := e.finalizeDelete(ctx, out, true, options)
        // clients are expecting an updated object if a PUT succeeded, but
        // finalizeDelete returns a metav1.Status, so return the object in
        // the request instead.
        return obj, false, err
}

// Update performs an atomic update and set of the object. Returns the result of the update
// or an error. If the registry allows create-on-update, the create flow will be executed.
// A bool is returned along with the object and any errors, to indicate object creation.
func (e *Store) Update(ctx context.Context, name string, objInfo rest.UpdatedObjectInfo, createValidation rest.ValidateObjectFunc, updateValidation rest.ValidateObjectUpdateFunc, forceAllowCreate bool, options *metav1.UpdateOptions) (runtime.Object, bool, error) {
        key, err := e.KeyFunc(ctx, name)
        if err != nil {
                return nil, false, err

return nil, false, err
        }

        var (
                creatingObj runtime.Object
                creating    = false
        )

        qualifiedResource := e.qualifiedResourceFromContext(ctx)
        storagePreconditions := &storage.Preconditions{}
        if preconditions := objInfo.Preconditions(); preconditions != nil {
                storagePreconditions.UID = preconditions.UID
                storagePreconditions.ResourceVersion = preconditions.ResourceVersion
        }

        out := e.NewFunc()

        // only ignore a not found error if this type allows creating on update, or we're forcing allowing create (like for server-side-apply)
        ignoreNotFound := e.UpdateStrategy.AllowCreateOnUpdate() || forceAllowCreate
        // deleteObj is only used in case a deletion is carried out
        var deleteObj runtime.Object
        err = e.Storage.GuaranteedUpdate(ctx, key, out, ignoreNotFound, storagePreconditions, func(existing runtime.Object, res storage.ResponseMeta) (runtime.Object, *uint64, error) {
                existingResourceVersion, err := e.Storage.Versioner().ObjectResourceVersion(existing)
                if err != nil {
                        return nil, nil, err
                }
                if existingResourceVersion == 0 {
                        if !e.UpdateStrategy.AllowCreateOnUpdate() && !forceAllowCreate {
                                return nil, nil, apierrors.NewNotFound(qualifiedResource, name)
                        }
                }

                // Given the existing object, get the new object
                obj, err := objInfo.UpdatedObject(ctx, existing)
                if err != nil {
                        return nil, nil, err
                }

                // If AllowUnconditionalUpdate() is true and the object specified by
                // the user does not have a resource version, then we populate it with
                // the latest version. Else, we check that the version specified by
                // the user matches the version of latest storage object.
                newResourceVersion, err := e.Storage.Versioner().ObjectResourceVersion(obj)
                if err != nil {
                        return nil, nil, err
                }
                doUnconditionalUpdate := newResourceVersion == 0 && e.UpdateStrategy.AllowUnconditionalUpdate()

                if existingResourceVersion == 0 {
                        // Init metadata as early as possible.
                        if objectMeta, err := meta.Accessor(obj); err != nil {
                                return nil, nil, err
                        } else {
                                rest.FillObjectMetaSystemFields(objectMeta)
                        }

                        var finishCreate FinishFunc = finishNothing

                        if e.BeginCreate != nil {
                                fn, err := e.BeginCreate(ctx, obj, newCreateOptionsFromUpdateOptions(options))
                                if err != nil {
                                        return nil, nil, err
                                }
                                finishCreate = fn
                                defer func() {
                                        finishCreate(ctx, false)
                                }()
                        }

                        creating = true
                        creatingObj = obj
                        if err := rest.BeforeCreate(e.CreateStrategy, ctx, obj); err != nil {
                                return nil, nil, err
                        }
                        // at this point we have a fully formed object.  It is time to call the validators that the apiserver
                        // handling chain wants to enforce.
                        if createValidation != nil {
                                if err := createValidation(ctx, obj.DeepCopyObject()); err != nil {
                                        return nil, nil, err
                                }
                        }
                        ttl, err := e.calculateTTL(obj, 0, false)
                        if err != nil {
                                return nil, nil, err
                        }

                        // The operation has succeeded.  Call the finish function if there is one,
                        // and then make sure the defer doesn't call it again.
                        fn := finishCreate
                        finishCreate = finishNothing
                        fn(ctx, true)

                        return obj, &ttl, nil
                }

                creating = false
                creatingObj = nil
                if doUnconditionalUpdate {
                        // Update the object's resource version to match the latest
                        // storage object's resource version.
                        err = e.Storage.Versioner().UpdateObject(obj, res.ResourceVersion)
                        if err != nil {
                                return nil, nil, err
                        }
                } else {
